  ('dietitian-moex-08444', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '我國在近年推行何種政策以提昇母乳哺育率，並獲初步成效？', '["提倡母嬰親善醫院", "減少嬰兒配方食品核准率", "提供乳婦營養品消費券", "免費贈送職場冰箱置放母乳"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08445', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '國人膳食營養素參考攝取量中針對日常生活活動強度分為：低、稍低、適度及高4個不同等級。請問其 中「適度」的生活活動強度指數為基礎代謝率（BMR）之幾倍？', '["1.9", "1.7", "1.5", "1.3"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
