  ('dietitian-moex-08447', 'dietitian', 'dietitian-moex-098-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '血清前白蛋白濃度可作為評估個人蛋白質營養狀況，此一指標之優點為：', '["不受肝臟疾病的影響", "不受慢性腎衰竭患者是否接受血液透析的影響", "較血清白蛋白更能快速反應飲食中增加蛋白質攝取量的情形", "半衰期比血清白蛋白長，能真正代表個人蛋白質營養狀況"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "83f743261448", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098020", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "098", "exam_name": "098年第一次專技醫事人員、中醫師、心理師、營養師、醫師分試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
